const GEMINI_API_KEY = 'REPLACE_WITH_GEMINI_API_KEY';

const input = $input.first().json;
const { content_id, image_prompt, framework_visual_type } = input.body || input;

if (!content_id || !image_prompt) {
  return [{ json: { success: false, error: 'content_id and image_prompt are required' } }];
}

try {
  const geminiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image:generateContent?key=${GEMINI_API_KEY}`;
  let geminiResp;
  try {
    geminiResp = await this.helpers.httpRequest({
      method: 'POST',
      url: geminiUrl,
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: image_prompt + '\n\nGenerate a 1:1 square image.' }] }],
        generationConfig: { responseModalities: ['IMAGE', 'TEXT'] }
      },
      json: true,
      timeout: 90000,
      ignoreHttpStatusErrors: true
    });
  } catch (geminiErr) {
    return [{ json: { success: false, error: `Gemini request failed: ${geminiErr.message}` } }];
  }

  if (geminiResp.error) {
    return [{ json: { success: false, error: `Gemini API error: ${JSON.stringify(geminiResp.error).slice(0, 300)}` } }];
  }

  let imageBase64 = null;
  let imageMimeType = 'image/png';
  if (geminiResp.candidates?.[0]?.content?.parts) {
    for (const part of geminiResp.candidates[0].content.parts) {
      if (part.inlineData) {
        imageBase64 = part.inlineData.data;
        imageMimeType = part.inlineData.mimeType || 'image/png';
        break;
      }
    }
  }
  if (!imageBase64) {
    return [{ json: { success: false, error: 'Gemini did not return an image' } }];
  }

  const ext = imageMimeType.includes('png') ? 'png' : imageMimeType.includes('webp') ? 'webp' : 'jpg';
  const fileName = `framework-illustrations/${content_id}-${Date.now()}.${ext}`;

  const binaryData = await this.helpers.prepareBinaryData(
    Buffer.from(imageBase64, 'base64'),
    `${content_id}.${ext}`,
    imageMimeType
  );

  return [{
    json: { success: true, content_id, fileName, imageMimeType },
    binary: { data: binaryData }
  }];
} catch (err) {
  return [{ json: { success: false, error: `Unexpected error: ${err.message}` } }];
}

const SUPABASE_URL = 'https://SUPABASE_PROJECT_REF.supabase.co';
const SUPABASE_KEY = 'REPLACE_WITH_SUPABASE_SERVICE_ROLE_KEY';

const prev = $node['Generate Image'].json;
if (!prev.success) {
  return [{ json: { success: false, error: prev.error } }];
}

const { content_id, fileName } = prev;
const imageUrl = `${SUPABASE_URL}/storage/v1/object/public/social-content/${fileName}`;

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/social_content_queue?id=eq.${content_id}`,
    headers: {
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'apikey': SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: { image_url: imageUrl },
    json: true,
    timeout: 10000
  });
} catch (dbErr) {
  return [{ json: { success: false, error: `DB update failed: ${dbErr.message}`, image_url: imageUrl } }];
}

return [{ json: { success: true, image_url: imageUrl, content_id } }];
